import os
import functools
import pickle

def create_cache(index_file):
    cache_dir = 'cache'
    if not os.path.exists(cache_dir):
        os.makedirs(cache_dir)

    cache_file = os.path.join(cache_dir, f'{os.path.basename(index_file)}.cache')
    return functools.lru_cache(maxsize=None)(cache_file)

def load_cache(cache_file):
    if os.path.exists(cache_file):
        with open(cache_file, 'rb') as f:
            return pickle.load(f)
    return {}

def save_cache(cache_file, cache):
    with open(cache_file, 'wb') as f:
        pickle.dump(cache, f)

def get_item_from_cache(index_file, key):
    cache = load_cache(create_cache(index_file))
    return cache.get(key)

def set_item_in_cache(index_file, key, value):
    cache = load_cache(create_cache(index_file))
    cache[key] = value
    save_cache(create_cache(index_file), cache)

